    public void test_TC01_O1() {
        // GIVEN: a known submittable tag "input" (pre-registered with formSubmit = true)
        Tag tag = Tag.valueOf("input");
        // WHEN: calling isFormSubmittable()
        boolean result = tag.isFormSubmittable();
        // THEN: it should return true because 'input' is a known tag marked submittable
        assertTrue(result, "Expected 'input' tag to be submittable by default");
    }

    @Test
    @DisplayName("TC02_O2: Overload with ParseSettings on known non-submittable tag returns false (formSubmit==false)")
    public void test_TC02_O2() {
        // GIVEN: a known non-submittable tag "div" (formSubmit defaults to false)
        ParseSettings settings = ParseSettings.preserveCase;
        Tag tag = Tag.valueOf("div", settings);
        // WHEN: calling isFormSubmittable()
        boolean result = tag.isFormSubmittable();
        // THEN: it should return false because 'div' is not in the submittable list
        assertFalse(result, "Expected 'div' tag to not be submittable even with custom ParseSettings");
    }

